          quad.topRight.x - quad.topLeft.x,
          quad.topRight.y - quad.topLeft.y
        );
        const bottomWidth = Math.hypot(
          quad.bottomRight.x - quad.bottomLeft.x,
          quad.bottomRight.y - quad.bottomLeft.y
        );
