  1036→/* ---------- Waiting Countdown ---------- */
  1037→
  1038→function WaitingCountdown() {
  1039→  const [remaining, setRemaining] = useState(120);
  1040→
  1041→  useEffect(() => {
  1042→    const timer = setInterval(() => {
  1043→      setRemaining((s) => {
  1044→        if (s <= 0) return 0;
  1045→        return s - 1;
  1046→      });
  1047→    }, 1000);
  1048→    return () => clearInterval(timer);
  1049→  }, []);
  1050→
  1051→  const minutes = Math.floor(remaining / 60);
  1052→  const seconds = remaining % 60;
  1053→
  1054→  return (
  1055→    <p style={{ color: "rgba(255,255,255,0.3)", fontSize: "0.9rem", marginTop: 24 }}>
  1056→      Auto-skip in {minutes}:{String(seconds).padStart(2, "0")}
  1057→    </p>
  1058→  );
  1059→}
