   661→        // Reset hold state
   662→        holdGestureRef.current = null;
   663→        holdStartRef.current = null;
   664→        setPendingGestureType(null);
   665→      }
   666→    };
   667→
   668→    holdRafRef.current = requestAnimationFrame(tick);
   669→    return () => cancelAnimationFrame(holdRafRef.current);
